import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import { verifyToken } from '@/lib/auth';

const prisma = new PrismaClient();

export const dynamic = 'force-dynamic';

// GET: دریافت یک فوتر
export async function GET(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const footer = await prisma.footer.findUnique({
      where: { id: params.id }
    });

    if (!footer) {
      return NextResponse.json({ 
        success: false,
        error: 'Footer not found' 
      }, { status: 404 });
    }

    return NextResponse.json({ 
      success: true,
      footer: {
        ...footer,
        contactInfo: footer.contactInfo ? JSON.parse(footer.contactInfo) : null,
        columns: JSON.parse(footer.columns || '[]'),
        bottomBar: footer.bottomBar ? JSON.parse(footer.bottomBar) : null,
        style: footer.style ? JSON.parse(footer.style) : null
      }
    });
  } catch (error) {
    console.error('Footer GET error:', error);
    return NextResponse.json({ 
      success: false,
      error: 'Internal server error' 
    }, { status: 500 });
  }
}

// PUT: آپدیت فوتر
export async function PUT(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const data = await request.json();

    const footer = await prisma.footer.update({
      where: { id: params.id },
      data: {
        companyName: data.companyName,
        tagline: data.tagline,
        description: data.description,
        contactInfo: JSON.stringify(data.contactInfo || {}),
        columns: JSON.stringify(data.columns || []),
        bottomBar: JSON.stringify(data.bottomBar || {}),
        style: JSON.stringify(data.style || {}),
        isActive: data.isActive
      },
    });

    return NextResponse.json({ 
      success: true,
      footer 
    });
  } catch (error) {
    console.error('Footer PUT error:', error);
    return NextResponse.json({ 
      success: false,
      error: 'Internal server error' 
    }, { status: 500 });
  }
}

// DELETE: حذف فوتر
export async function DELETE(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    await prisma.footer.delete({
      where: { id: params.id }
    });

    return NextResponse.json({ 
      success: true,
      message: 'Footer deleted successfully' 
    });
  } catch (error) {
    console.error('Footer DELETE error:', error);
    return NextResponse.json({ 
      success: false,
      error: 'Internal server error' 
    }, { status: 500 });
  }
}
